VALUES
  ('social-worker-moex-05500', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '信賴區間乃利用樣本統計量（sample statistic）加上誤差的考量，形成數值區間來推論群體的參數（population parameter），下列有關「信賴區間」的敘述，何者錯誤？', '["信賴區間的寬窄會受到樣本大小及群體標準差大小的影響", "當樣本增大時信賴區間的寬度會變窄", "信心水準愈高其信賴區間寬度會愈窄", "在常態分配下樣本平均數約有95%的機會落在群體平均數±1.96個標準誤之內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05501', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關問卷設計一些相關注意事項，下列敘述何者錯誤？', '["涉及敏感或隱私的題項，應儘量放在後面", "有時為了避免影響填答者的情緒，個人基本資料的填答，可放在問卷最後", "為了避免填答時不看清楚問卷就作答，問卷的題項可以用隨機的方式安排其出現順序", "應避免問填答者無法回答或從未聽過的問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05502', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關測量尺度的敘述，何者正確？', '["溫度、年齡屬於同一測量尺度", "如將婚姻狀況分為已婚、未婚是屬於名目層次的測量", "如果將滿意度從非常不滿意、不滿意、不確定、滿意、到非常滿意的分類賦予1、2、3、4、5的數據， 是屬於等距層次資料", "不同測量尺度資料只要化成數據，可以用相同的統計方法分析"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05503', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在抽樣的過程中，從群體到樣本，涵蓋不同數目的抽樣單位，下列何者排列符合「由多而少」的抽樣範圍？', '["理論群體 研究群體 抽樣架構 抽樣單位", "研究群體 理論群體 抽樣架構 抽樣單位", "理論群體 抽樣架構 研究群體 抽樣單位", "研究群體 抽樣架構 理論群體 抽樣單位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05504', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於行動研究（action research）的敘述，下列何者正確？', '["針對面臨到的問題，不斷整合專家學者們的智識與智慧，並設計問卷進行調查，是集合專家意見的集 體決策技術", "研究團隊人員在進行方案的過程中，可將方案與研究方案過程中產生的問題一併執行，以便進行研究 又能解決問題", "是在事情發生後以調查研究的方式，著手分析其原因的研究方法", "步驟為：形成研究問題→測量→實驗設計→分析研究成功或失敗的原因"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05505', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者運用半結構式的訪談對罹患慢性疾病患者進行調查，觀察到許多男性慢性疾病患者發展出一套自 我保存的策略以免於陷入憂鬱。這種由資料來建構理論的推理過程，稱為：', '["演繹法", "歸納法", "實證主義", "假說檢定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05506', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於一個質化訪談的完整過程，下列各階段的順序何者正確？', '["訂出主題－設計－訪談－謄寫－分析－確認－報導", "訂出主題－訪談－設計－分析－謄寫－報導－確認", "訂出主題－設計－訪談－分析－謄寫－報導－確認", "訂出主題－謄寫－分析－訪談－報導－確認－設計"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05507', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在進行推論統計時，研究人員無可避免地必須承擔錯誤的風險，名為第一型錯誤（type I error）與第二型 錯誤（type II error）。今當顯著水準由0.05變更為0.01時，犯上述錯誤的風險會如何改變？', '["犯第一型錯誤的風險降低，犯第二型錯誤的風險提高", "犯第一型錯誤的風險提高，犯第二型錯誤的風險降低", "犯第一型錯誤的風險降低，犯第二型錯誤的風險不變", "犯第一型錯誤的風險不變，犯第二型錯誤的風險降低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05508', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關分層隨機抽樣（stratified sampling）與集叢取樣法（cluster sampling）中「層」與「集叢」的概念， 下列何者正確？', '["層內異質性高，集叢內同質性高", "層內同質性高，集叢內異質性高", "層與層間異質性高，集叢與集叢間異質性亦高", "層與層間同質性高，集叢與集叢間異質性高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05509', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當研究人員在進行變異數分析（ANOVA）時，若組內離均差平方和（within-group sum of squares）變成 原來的2倍時，在其餘條件都不變的情況下，所計算出來的F值會成為原來的多少？', '["1/4", "1/2", "2倍", "4倍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
